#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int target; cin >> target;
    int left = 0;
    int right = n - 1;
    int first_occurrence = -1;
    while(left <= right){
        int mid = (left + right) / 2;
        if(nums[mid] == target){
            first_occurrence = mid;
            right = mid - 1;
        } else if(nums[mid] < target){
            left = mid + 1;
        } else{
            right = mid - 1;
        }
    }
    if(first_occurrence == -1){
        cout << 0;
    } else{
        left = 0;
        right = n - 1;
        int last_occurrence = -1;
        while(left <= right){
            int mid = (left + right) / 2;
            if(nums[mid] == target){
                last_occurrence = mid;
                left = mid + 1;
            } else if(nums[mid] < target){
                left = mid + 1;
            } else{
                right = mid - 1;
            }
        }
        cout << last_occurrence - first_occurrence + 1;
    }
}
